export var SET_WINDOW = "SET_WINDOW";
export var TOGGLE_MENU = "TOGGLE_MENU";
export var OPEN_MENU = "OPEN_MENU";
export var ADD_CLASS_TO_CURSOR = "ADD_CLASS_TO_CURSOR";
export var REMOVE_CLASS_FROM_CURSOR = "REMOVE_CLASS_FROM_CURSOR";
export var HIDE_FULL_SCREEN_VIDEO = "HIDE_FULL_SCREEN_VIDEO";
export var SHOW_FULL_SCREEN_VIDEO = "SHOW_FULL_SCREEN_VIDEO";
export var SET_MENU_BTN_COLOR = "SET_MENU_BTN_COLOR";
export function showFullscreenVideo(video_id, video_src, video_type) {
  return {
    type: SHOW_FULL_SCREEN_VIDEO,
    video_id: video_id,
    video_src: video_src,
    video_type: video_type
  };
}
export function hideFullscreenVideo() {
  return {
    type: HIDE_FULL_SCREEN_VIDEO
  };
}
export function setWindow(windowWidth, windowHeight) {
  return {
    type: SET_WINDOW,
    windowWidth: windowWidth,
    windowHeight: windowHeight
  };
}
export function toggleMenu() {
  return {
    type: TOGGLE_MENU
  };
}
export function openMenu(bool) {
  return {
    type: OPEN_MENU,
    bool: bool
  };
}
export function addClassToCursor(cls) {
  return {
    type: ADD_CLASS_TO_CURSOR,
    cls: cls
  };
}
export function setMenuBtnColor(color) {
  return {
    type: SET_MENU_BTN_COLOR,
    color: color
  };
}
export function removeClassFromCursor(cls) {
  return {
    type: REMOVE_CLASS_FROM_CURSOR,
    cls: cls
  };
}
